
@use '../styles/_glass.scss' as glass;

.character-card {
  display: flex;
  flex-direction: row;
  gap: 16px;
  padding: 4px 8px 8px;
  width: 100%;
  box-sizing: border-box;
  flex-shrink: 0;
}

.info-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 10px;
  min-width: 0;
}

@media (max-width: 480px) {
  .character-card {
    flex-direction: column;
    padding: 4px;
  }
}
